import {
  VerticalTimeline,
  VerticalTimelineElement,
} from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";
import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const experienceData = [
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2024",
    icon: <FaUniversity />,
  },
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022-Present",
    icon: <FaBriefcase />,
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022",
    icon: <FaUniversity />,
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021-2022",
    icon: <FaBriefcase />,
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014-2021",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013-2014",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008-2013",
    icon: <FaBriefcase />,
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001-2008",
    icon: <FaBriefcase />,
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001-2006",
    icon: <FaUniversity />,
  },
];

const getGradient = (icon) => {
  if (icon.type === FaBriefcase) return "bg-gradient-to-r from-black to-white";
  return "bg-gradient-to-r from-blue-600 to-white";
};

const getSizeClass = (icon) => {
  if (icon.type === FaBriefcase) return "text-base";
  return "text-sm";
};

const ExperienceTimeline = () => {
  return (
    <div className="w-fit mx-auto">
      <VerticalTimeline>
        {experienceData.map((exp, index) => (
          <VerticalTimelineElement
            key={index}
            date={<span className="text-gray-800 font-medium">{exp.date}</span>}
            iconStyle={{ background: "transparent", display: "flex", alignItems: "center", justifyContent: "center" }}
            icon={
              <div
                className={`rounded-full p-3 ${getGradient(exp.icon)} text-white text-lg`}
              >
                {exp.icon}
              </div>
            }
            contentStyle={{
              background: "#f3f4f6",
              color: "#111827",
              boxShadow: "0 4px 6px rgba(0,0,0,0.1)",
              padding: "0.75rem 1rem",
              width: "fit-content",
              maxWidth: "100%",
            }}
            contentArrowStyle={{ borderRight: "7px solid #f3f4f6" }}
          >
            <h3 className={`font-semibold ${getSizeClass(exp.icon)}`}>{exp.title}</h3>
            <p className="text-gray-600 text-sm">{exp.company}</p>
          </VerticalTimelineElement>
        ))}
      </VerticalTimeline>
    </div>
  );
};

export default ExperienceTimeline;
